<?php
namespace app\Repositories; class BookRepository extends BaseRepository{ public function paginate(string $q='',int $page=1,int $perPage=10):array{$offset=($page-1)*$perPage;$where='';$params=[];if($q){$where="WHERE b.title LIKE ? OR b.isbn LIKE ? OR b.author LIKE ?";$params=["%$q%","%$q%","%$q%"];}$total=(int)$this->fetch("SELECT COUNT(*) c FROM books b $where",$params)['c'];return ['data'=>$this->fetchAll("SELECT b.*,t.name type_name FROM books b LEFT JOIN book_types t ON t.id=b.book_type_id $where ORDER BY b.id DESC LIMIT $perPage OFFSET $offset",$params),'total'=>$total];} public function all():array{return $this->fetchAll("SELECT b.*,t.name type_name FROM books b LEFT JOIN book_types t ON t.id=b.book_type_id ORDER BY b.title");} public function find(int $id):?array{return $this->fetch("SELECT b.*,t.name type_name FROM books b LEFT JOIN book_types t ON t.id=b.book_type_id WHERE b.id=?",[$id]);} public function create(array $d):int{$this->execute("INSERT INTO books(isbn,title,book_type_id,author,publisher,publish_year,quantity,price,description) VALUES(?,?,?,?,?,?,?,?,?)",[$d['isbn'],$d['title'],$d['book_type_id'],$d['author'],$d['publisher']??null,$d['publish_year']??null,$d['quantity'],$d['price']??0,$d['description']??null]);return $this->lastInsertId();} public function update(int $id,array $d):bool{return $this->execute("UPDATE books SET isbn=?,title=?,book_type_id=?,author=?,publisher=?,publish_year=?,quantity=?,price=?,description=? WHERE id=?",[$d['isbn'],$d['title'],$d['book_type_id'],$d['author'],$d['publisher']??null,$d['publish_year']??null,$d['quantity'],$d['price']??0,$d['description']??null,$id]);} public function delete(int $id):bool{return $this->execute("DELETE FROM books WHERE id=?",[$id]);} public function hasBorrowHistory(int $id):bool{return (int)$this->fetch("SELECT COUNT(*) c FROM borrows WHERE item_type='book' AND item_id=?",[$id])['c']>0;}}
